export type OneTimePurchase = {
  provider: string;
  providerOrderId: string;
  productKey: string;
  amount: number;
  currency: string;
  status?: "pending" | "paid" | "failed" | "refunded" | "disputed";
  fulfillmentStatus?: "pending" | "fulfilled" | "failed";
  metadata?: Record<string, unknown>;
};

export function createOneTimePurchase(purchase: OneTimePurchase) {
  if (!Number.isInteger(purchase.amount) || purchase.amount < 0) {
    throw new Error("Purchase amount must be a non-negative integer in the smallest currency unit.");
  }

  return {
    ...purchase,
    status: purchase.status ?? "pending",
    fulfillmentStatus: purchase.fulfillmentStatus ?? "pending",
    metadata: purchase.metadata ?? {},
  };
}

export function canFulfillPurchase(purchase: OneTimePurchase) {
  return purchase.status === "paid" && (purchase.fulfillmentStatus ?? "pending") === "pending";
}

const checklist = [
  "Create orders server-side before redirecting to checkout.",
  "Mark orders paid from verified provider events.",
  "Fulfill each paid order once.",
  "Link refunds and disputes back to the original order.",
];

export default function OneTimePurchasesPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">One-Time Purchases</h1>
        <p className="text-muted-foreground">One-off payments, add-ons, lifetime deals, and fulfillment tracking.</p>
      </div>
      <div className="grid gap-3">
        {checklist.map((item) => (
          <div key={item} className="rounded-lg border p-4 text-sm">{item}</div>
        ))}
      </div>
    </main>
  );
}
